案例代码：
entity top_ENT is
port(Clk:in std_logic;
     Rst:in std_logic;
     D_in:in std_logic;
     D_out:out std_logic);
end top_ENT;
architecture behave_ARC of top is
   signal S_Dout1_r, S_Dout_temp_r: std_logic;
begin
   process (Clk, Rst)
   begin
   if Rst= '0' then
     S_Dout_temp_r <= 0;
   elsif Clk’event and clk='1'then ----此处使用时钟信号上升沿
     S_Dout_temp_r <= D_in;
   end if;
   end;
   process (Clk, Rst)
   begin
   if Rst= '0' then
     S_Dout_temp_r <= 0;
   elsif Clk’event and clk='0'then ----此处使用时钟信号下降沿
     D_out <= S_Dout_temp_r;
   end if;
   end;
end behave_ARC;

