entity test_ENT is port(
	clk: in std_logic;
	rst: in std_logic;
	d_in: in std_logic;
	Sset: in std_logic;
	d_out:out std_logic );
	……
	signal d_out: std_logic;
process (clk ,Sset , rst)
begin
	if rst ='0' then
		d_out <= 1'b0;
	else if (Sset='1')
		d_out <= 1'b1;
	else if clk’event and clk=’1’then
		d_out <= d_in;
	end if;
end process;
end behave_ARC;

