  entity dff is
	port (
	clk : in std_logic;
	D : in std_logic;
	Q : out std_logic
	);
  end dff;

  architecture basic of dff is
  begin
  process(clk) is
  begin
	if(clk'event and clk = '1') then
	  Q <= D;
	end if;
  end process;
  end basic;

  entity R6_2_11_2_1 is   --violation
	port (	
	CLK1 : in std_logic; 
	CLK2 : in std_logic; 
	D : in std_logic;
	Q1 : out std_logic;
	Q2 : out std_logic
	);
  end R6_2_11_2_1;

  architecture behave of R6_2_11_2_1 is

	signal D_n : std_logic;
	signal ff_out : std_logic;
  begin
	D_n <= not D;
	DFF1 : entity dff
	port map(
	  CLK => CLK1,
	  D => D,
	  Q => Q1
	);
	DFF2 : entity dff
	port map(
	  CLK => CLK2,
	  D => D,
	  Q => Q2
	);

  );
  end behave;

