	案例代码：
	entity example_ENT is
	   port(clk : in std_logic;
             rst: in std_logic;
             sel1: in std_logic;
             sel2: in std_logic;
             din: in std_logic;
             dout: out std_logic);
    end example_ENT;
    architecture behave_ARC of example_ARC is
    signal clk1:std_logic;
    signal clk2: std_logic;
    signal clk_sel: std_logic;
    begin
      clk1 <= sel1 and clk;
      clk2 <= sel2 or clk;
      clk_sel <= clk1 and clk2;--此处的时钟信号在时钟网络上发生了再汇聚
    process(rst,clk_sel)
    begin
      if(rst='0')then
        dout <= ’0’;
      elsif clk_sel’event and clk_sel =’1’ then
        dout <= din;
      end if;
   end process;
   end behave_ARC;

