......
--第一个进程，同步时序进程，格式化描述次态寄存器迁移到现态寄存器
process(rst_n,clk)
begin
  if rst_n ='0' then
    current_state_r <= IDLE;
  elsif rising_edge(clk) then
    current_state_r <= next_state_r;
  end if;
end process;
......
--第二个进程，组合逻辑进程，描述状态转移条件判断
process(current_state_r, AD_start,…)
begin
  next_state_r <= IDLE;
  case current_state_r is
    when IDLE =>
      if AD_start='1' then
		next_state_r <= STATE_1;
	  else
		next_state_r <= IDLE;
	  end if;
	when STATE_1=>
	  next_state_r <= STATE_2;
	  ......
	when others=>
	  next_state_r <= IDLE;
  end case;
end process;
--第三个进程，同步时序进程，格式化描述次态寄存器输出
process(rst_n,clk)
begin
  if rst_n ='0' then
	AD_CS<='1';
	AD_RD<='1';
	AD_DONE<='0';
	......
  elsif rising_edge(clk) then
	case next_state_r is
	  when IDLE =>
		AD_CS<='1';
		AD_RD<='1';
		AD_DONE<='0';
		......
	  when STATE_1=>
		AD_CS<='0';
		......
	end case;
  end if;
end process;

