entity sig_ENT is 
port(
	reset: in std_logic;
	clk : in std_logic;
	cnt_out: out std_logic_vector(5 downto 0)
	);
end sig_ENT;
architecture behave_ARC of sig_ENT is
	signal S_count:std_logic_vector(7 downto 0);
begin
cnt_out <= S_count(5 downto 0);
process(reset,clk)
begin
	if reset='0' then
		S_count <= X"00";
	elsif rising_edge(clk) then
		S_count <= count +1;
