architecture behave_arc of example_ent is 
constant CTMP : std_logic : = '1'; 
constant CFS_COND : std_logic : = '1'; begin 
process (SEL_in, A_in) 
  begin
    case (CFS_COND) is    ---- case语句的条件表达式不应为常量
	  when CTMP  => A_out <= A_in;
	  when others => A_out <= 'X'; 
	end case; 
end process; 
end behave_arc;

