--------输出信号反馈驱动同模块内部逻辑------
ENTITY top_ENT IS
	PORT ( A_in：IN STD_LOGIC ；
			B_in：IN STD_LOGIC ；
			CLK ：IN STD_LOGIC ；
			A_r_out：OUT STD_LOGIC;
			B_out：OUT STD_LOGIC）;
end ENTITY;
	ARCHITECTURE behave_ARC OF top_ENT IS
	begin
	B_out <= B_in and A_r_out; ---输出端口A_r_out 在模块内部用来驱动 B_out
	PROCESS (CLK, A_in)
	begin
	if clk'event and clk='1' then
		A_r_out <= A_in;
	end if;
	end process;
	end behave_ARC;

